cy.intercept("POST", "/api/forgotPassword/*", {
  statusCode: 200,
  body: {
    msg: "Email sent successfully",
    resetToken: "mock-token"
  }
}).as("forgotReq");
_LidarViewer.default.emailInForgotPasswordField.type(_Constants.default.validForgotEmail);
_LidarViewer.default.sendRecoverLinkBtn.click();
cy.wait("@forgotReq").then(interception => {
  expect(interception.response.statusCode).to.eq(200);
  expect(interception.response.body.msg).to.eq("Email sent successfully");
  expect(interception.response.body.resetToken).to.exist;
});
